SELECT * FROM ( SELECT ROW_NUMBER() OVER ( ORDER BY A1.PRO_ID) AS RNUM , COALESCE(A1.REQ_ID, '') AS REQ_ID , COALESCE(A1.PRO_ID, '') AS PRO_ID , COALESCE(A1.PRO_SEQ, '0') AS PRO_SEQ , COALESCE(A1.REQ_PRO_SEQ, '0') AS REQ_PRO_SEQ , COALESCE(A1.REQ_ESNTL_ID, '') AS REQ_ESNTL_ID , COALESCE(A1.C_ESNTL_ID, '') AS C_ESNTL_ID , COALESCE(DECRYPT(U.USER_NM), '') AS USER_NM , COALESCE(FN_MASK_PHONE(COALESCE(DECRYPT(U.MBTLNUM), ''), 'N'), '') AS C_MBTLNUM , COALESCE(U.SEXDSTN_CODE, '') AS C_SEXDSTN_CODE , COALESCE(U.BRTHDY, '') AS C_BRTHDY , COALESCE(DECRYPT(A1.HEAD_NM), '') AS HEAD_NM , COALESCE(A1.P_ESNTL_ID, '') AS P_ESNTL_ID , COALESCE(DECRYPT(A1.P_USER_NM), '') AS P_USER_NM , COALESCE(A1.PRO_TYPE, '') AS PRO_TYPE , CASE WHEN A1.PRO_TYPE = '01' THEN '1인탐구형' WHEN A1.PRO_TYPE = '02' THEN '모둠탐구형' ELSE '' END AS PRO_TYPE_NM , COALESCE(FN_MASK_PHONE(COALESCE(DECRYPT(A1.MBTLNUM), ''), 'N'), '') AS MBTLNUM , COALESCE(A1.BRTHDY, '') AS BRTHDY , COALESCE(DECRYPT(A1.P_IHIDNUM), '') AS P_IHIDNUM , COALESCE(DECRYPT(A1.C_IHIDNUM), '') AS C_IHIDNUM , COALESCE(A1.CERT_YN, 'N') AS CERT_YN , COALESCE(A1.SCHOOL_ID, '') AS SCHOOL_ID , COALESCE(A1.SCHOOL_GB, '') AS SCHOOL_GB , COALESCE(A1.SCHOOL_NM, '') AS SCHOOL_NM , COALESCE(A1.SCHOOL_LVL, 0) AS SCHOOL_LVL , COALESCE(A1.SCHOOL_NO, 0) AS SCHOOL_NO , CASE WHEN A1.SCHOOL_LVL IS NOT NULL AND A1.SCHOOL_NO IS NOT NULL THEN CONCAT(A1.SCHOOL_LVL, '학년 ', A1.SCHOOL_NO, '반') WHEN A1.SCHOOL_LVL IS NOT NULL THEN CONCAT(A1.SCHOOL_LVL, '학년') WHEN A1.SCHOOL_NO IS NOT NULL THEN CONCAT(A1.SCHOOL_NO, '반') ELSE '' END AS SCHOOL_CLASS , COALESCE(A1.PAY_BANK_CODE, '') AS PAY_BANK_CODE , COALESCE((select CODE_NM from LETTCCMMNDETAILCODE where CODE_ID = 'ARM002' and CODE = A1.PAY_BANK_CODE), '' ) as PAY_BANK_CODE_NM , COALESCE(A1.PAY_BANK, '') AS PAY_BANK , COALESCE(A1.HOLDER_NM, '') AS HOLDER_NM , COALESCE(A1.REQ_PART, '') AS REQ_PART , COALESCE(A1.PLAY_PART, '') AS PLAY_PART , COALESCE(A1.REQ_OBJ, '') AS REQ_OBJ , COALESCE(A1.REQ_PLAY, '') AS REQ_PLAY , COALESCE(A1.REQ_PLAN, '') AS REQ_PLAN , COALESCE(A1.MCHIL_YN, 'N') AS MCHIL_YN , COALESCE(A1.MCHIL_NM, '') AS MCHIL_NM , COALESCE(A1.REQ_DESC, '') AS REQ_DESC , COALESCE(A1.FILE_ID, '') AS FILE_ID , COALESCE(A1.RESULT_GB, '') AS RESULT_GB , A1.REQ_DT , A1.APRR_DT , A1.CHG_DT , A1.STOP_DT , COALESCE(A1.REA_DESC, '') AS REA_DESC , COALESCE(A1.STTUS_CODE, '') AS STTUS_CODE , CASE WHEN A1.STTUS_CODE = '01' THEN '임시저장' WHEN A1.STTUS_CODE = '02' THEN '신청' WHEN A1.STTUS_CODE = '03' THEN '승인' WHEN A1.STTUS_CODE = '04' THEN '완료' WHEN A1.STTUS_CODE = '11' THEN '반려' WHEN A1.STTUS_CODE = '12' THEN '중단' WHEN A1.STTUS_CODE = '99' THEN '취소' ELSE '' END AS STTUS_CODE_NM , COALESCE(A1.CHG_USER_ID, '') AS CHG_USER_ID , A1.CRT_DATE , A1.CHG_DATE , A2.WORK_DATE , A2.START_TIME , COALESCE(A2.ITEM1, '') AS ITEM1 , COALESCE(A2.ITEM2, '') AS ITEM2 , COALESCE(A2.ITEM3, '') AS ITEM3 , COALESCE(A2.ITEM4, '') AS ITEM4 , COALESCE(DECRYPT(U.ZIP), '') AS ZIP , COALESCE(DECRYPT(U.ADRES), '') AS ADRES , COALESCE(DECRYPT(U.DETAIL_ADRES), '') AS DETAIL_ADRES , COALESCE(CONCAT(DECRYPT(U.ADRES), ' ', DECRYPT(U.DETAIL_ADRES)), '') AS FULL_ADRES FROM ARTAPPM A1 LEFT JOIN ARTPROD A2 ON A1.PRO_ID = A2.PRO_ID AND A1.PRO_SEQ = A2.PRO_SEQ LEFT JOIN ARMUSER U ON A1.C_ESNTL_ID = U.ESNTL_ID LEFT JOIN ARMUSER PU ON A1.P_ESNTL_ID = PU.ESNTL_ID WHERE 1 = 1 AND A1.PRO_ID = #{searchProId}
AND DECRYPT(U.USER_NM) LIKE CONCAT('%', #{searchUserNm}, '%')
) A0 LIMIT #{lengthPage} OFFSET #{startIndex}

SELECT * FROM ( SELECT ROW_NUMBER() OVER ( ORDER BY A1.PRO_ID) AS RNUM , COALESCE(A1.REQ_ID, '') AS REQ_ID , COALESCE(A1.PRO_ID, '') AS PRO_ID , COALESCE(A1.PRO_SEQ, '0') AS PRO_SEQ , COALESCE(A1.REQ_PRO_SEQ, '0') AS REQ_PRO_SEQ , COALESCE(A1.REQ_ESNTL_ID, '') AS REQ_ESNTL_ID , COALESCE(A1.C_ESNTL_ID, '') AS C_ESNTL_ID , COALESCE(DECRYPT(U.USER_NM), '') AS USER_NM , COALESCE(FN_MASK_PHONE(COALESCE(DECRYPT(U.MBTLNUM), ''), 'N'), '') AS C_MBTLNUM , COALESCE(U.SEXDSTN_CODE, '') AS C_SEXDSTN_CODE , COALESCE(U.BRTHDY, '') AS C_BRTHDY , COALESCE(DECRYPT(A1.HEAD_NM), '') AS HEAD_NM , COALESCE(A1.P_ESNTL_ID, '') AS P_ESNTL_ID , COALESCE(DECRYPT(A1.P_USER_NM), '') AS P_USER_NM , COALESCE(A1.PRO_TYPE, '') AS PRO_TYPE , CASE WHEN A1.PRO_TYPE = '01' THEN '1인탐구형' WHEN A1.PRO_TYPE = '02' THEN '모둠탐구형' ELSE '' END AS PRO_TYPE_NM , COALESCE(FN_MASK_PHONE(COALESCE(DECRYPT(A1.MBTLNUM), ''), 'N'), '') AS MBTLNUM , COALESCE(A1.BRTHDY, '') AS BRTHDY , COALESCE(DECRYPT(A1.P_IHIDNUM), '') AS P_IHIDNUM , COALESCE(DECRYPT(A1.C_IHIDNUM), '') AS C_IHIDNUM , COALESCE(A1.CERT_YN, 'N') AS CERT_YN , COALESCE(A1.SCHOOL_ID, '') AS SCHOOL_ID , COALESCE(A1.SCHOOL_GB, '') AS SCHOOL_GB , COALESCE(A1.SCHOOL_NM, '') AS SCHOOL_NM , COALESCE(A1.SCHOOL_LVL, 0) AS SCHOOL_LVL , COALESCE(A1.SCHOOL_NO, 0) AS SCHOOL_NO , CASE WHEN A1.SCHOOL_LVL IS NOT NULL AND A1.SCHOOL_NO IS NOT NULL THEN CONCAT(A1.SCHOOL_LVL, '학년 ', A1.SCHOOL_NO, '반') WHEN A1.SCHOOL_LVL IS NOT NULL THEN CONCAT(A1.SCHOOL_LVL, '학년') WHEN A1.SCHOOL_NO IS NOT NULL THEN CONCAT(A1.SCHOOL_NO, '반') ELSE '' END AS SCHOOL_CLASS , COALESCE(A1.PAY_BANK_CODE, '') AS PAY_BANK_CODE , COALESCE((select CODE_NM from LETTCCMMNDETAILCODE where CODE_ID = 'ARM002' and CODE = A1.PAY_BANK_CODE), '' ) as PAY_BANK_CODE_NM , COALESCE(A1.PAY_BANK, '') AS PAY_BANK , COALESCE(A1.HOLDER_NM, '') AS HOLDER_NM , COALESCE(A1.REQ_PART, '') AS REQ_PART , COALESCE(A1.PLAY_PART, '') AS PLAY_PART , COALESCE(A1.REQ_OBJ, '') AS REQ_OBJ , COALESCE(A1.REQ_PLAY, '') AS REQ_PLAY , COALESCE(A1.REQ_PLAN, '') AS REQ_PLAN , COALESCE(A1.MCHIL_YN, 'N') AS MCHIL_YN , COALESCE(A1.MCHIL_NM, '') AS MCHIL_NM , COALESCE(A1.REQ_DESC, '') AS REQ_DESC , COALESCE(A1.FILE_ID, '') AS FILE_ID , COALESCE(A1.RESULT_GB, '') AS RESULT_GB , A1.REQ_DT , A1.APRR_DT , A1.CHG_DT , A1.STOP_DT , COALESCE(A1.REA_DESC, '') AS REA_DESC , COALESCE(A1.STTUS_CODE, '') AS STTUS_CODE , CASE WHEN A1.STTUS_CODE = '01' THEN '임시저장' WHEN A1.STTUS_CODE = '02' THEN '신청' WHEN A1.STTUS_CODE = '03' THEN '승인' WHEN A1.STTUS_CODE = '04' THEN '완료' WHEN A1.STTUS_CODE = '11' THEN '반려' WHEN A1.STTUS_CODE = '12' THEN '중단' WHEN A1.STTUS_CODE = '99' THEN '취소' ELSE '' END AS STTUS_CODE_NM , COALESCE(A1.CHG_USER_ID, '') AS CHG_USER_ID , A1.CRT_DATE , A1.CHG_DATE , A2.WORK_DATE , A2.START_TIME , COALESCE(A2.ITEM1, '') AS ITEM1 , COALESCE(A2.ITEM2, '') AS ITEM2 , COALESCE(A2.ITEM3, '') AS ITEM3 , COALESCE(A2.ITEM4, '') AS ITEM4 , COALESCE(DECRYPT(U.ZIP), '') AS ZIP , COALESCE(DECRYPT(U.ADRES), '') AS ADRES , COALESCE(DECRYPT(U.DETAIL_ADRES), '') AS DETAIL_ADRES , COALESCE(CONCAT(DECRYPT(U.ADRES), ' ', DECRYPT(U.DETAIL_ADRES)), '') AS FULL_ADRES FROM ARTAPPM A1 LEFT JOIN ARTPROD A2 ON A1.PRO_ID = A2.PRO_ID AND A1.PRO_SEQ = A2.PRO_SEQ LEFT JOIN ARMUSER U ON A1.C_ESNTL_ID = U.ESNTL_ID LEFT JOIN ARMUSER PU ON A1.P_ESNTL_ID = PU.ESNTL_ID WHERE 1 = 1 AND A1.PRO_ID = #{searchProId}
AND DECRYPT(U.USER_NM) LIKE CONCAT('%', #{searchUserNm}, '%')
) A0

SELECT COALESCE(A1.REQ_ID, '') AS REQ_ID , COALESCE(A1.PRO_ID, '') AS PRO_ID , COALESCE(A1.PRO_SEQ, '0') AS PRO_SEQ , COALESCE(A1.REQ_ESNTL_ID, '') AS REQ_ESNTL_ID , COALESCE(A1.C_ESNTL_ID, '') AS C_ESNTL_ID , COALESCE(DECRYPT(U.USER_NM), '') AS USER_NM , COALESCE(FN_MASK_PHONE(COALESCE(DECRYPT(U.MBTLNUM), ''), 'N'), '') AS C_MBTLNUM , COALESCE(U.SEXDSTN_CODE, '') AS C_SEXDSTN_CODE , COALESCE(U.BRTHDY, '') AS C_BRTHDY , COALESCE(DECRYPT(A1.HEAD_NM), '') AS HEAD_NM , COALESCE(A1.P_ESNTL_ID, '') AS P_ESNTL_ID , COALESCE(DECRYPT(A1.P_USER_NM), '') AS P_USER_NM , COALESCE(A1.PRO_TYPE, '') AS PRO_TYPE , COALESCE(FN_MASK_PHONE(COALESCE(DECRYPT(A1.MBTLNUM), ''), 'N'), '') AS MBTLNUM , COALESCE(A1.BRTHDY, '') AS BRTHDY , COALESCE(DECRYPT(A1.P_IHIDNUM), '') AS P_IHIDNUM , COALESCE(DECRYPT(A1.C_IHIDNUM), '') AS C_IHIDNUM , COALESCE(A1.CERT_YN, 'N') AS CERT_YN , COALESCE(A1.SCHOOL_ID, '') AS SCHOOL_ID , COALESCE(A1.SCHOOL_GB, '') AS SCHOOL_GB , COALESCE(A1.SCHOOL_NM, '') AS SCHOOL_NM , COALESCE(A1.SCHOOL_LVL, 0) AS SCHOOL_LVL , COALESCE(A1.SCHOOL_NO, 0) AS SCHOOL_NO , COALESCE(A1.PAY_BANK_CODE, '') AS PAY_BANK_CODE , COALESCE((SELECT CODE_NM FROM LETTCCMMNDETAILCODE WHERE CODE_ID = 'ARM002' AND CODE = A1.PAY_BANK_CODE), '') AS PAY_BANK_CODE_NM , COALESCE(A1.PAY_BANK, '') AS PAY_BANK , COALESCE(A1.HOLDER_NM, '') AS HOLDER_NM , COALESCE(A1.REQ_PART, '') AS REQ_PART , COALESCE(A1.PLAY_PART, '') AS PLAY_PART , COALESCE(A1.REQ_OBJ, '') AS REQ_OBJ , COALESCE(A1.REQ_PLAY, '') AS REQ_PLAY , COALESCE(A1.REQ_PLAN, '') AS REQ_PLAN , COALESCE(A1.MCHIL_YN, 'N') AS MCHIL_YN , COALESCE(A1.MCHIL_NM, '') AS MCHIL_NM , COALESCE(A1.REQ_DESC, '') AS REQ_DESC , COALESCE(A1.REA_DESC, '') AS REA_DESC , COALESCE(A1.FILE_ID, '') AS FILE_ID , COALESCE(A1.STUDY_CERT, '') AS STUDY_CERT , COALESCE(A1.STTUS_CODE, '') AS STTUS_CODE , CASE WHEN A1.STTUS_CODE = '01' THEN '임시저장' WHEN A1.STTUS_CODE = '02' THEN '신청' WHEN A1.STTUS_CODE = '03' THEN '승인' WHEN A1.STTUS_CODE = '04' THEN '완료' WHEN A1.STTUS_CODE = '11' THEN '반려' WHEN A1.STTUS_CODE = '12' THEN '중단' WHEN A1.STTUS_CODE = '99' THEN '취소' ELSE '' END AS STTUS_CODE_NM , COALESCE(DECRYPT(U.ZIP), '') AS ZIP , COALESCE(DECRYPT(U.ADRES), '') AS ADRES , COALESCE(DECRYPT(U.DETAIL_ADRES), '') AS DETAIL_ADRES , DATE_FORMAT(A1.WORK_DT, '%Y-%m-%d') AS WORK_DT FROM ARTAPPM A1 LEFT JOIN ARMUSER U ON A1.C_ESNTL_ID = U.ESNTL_ID WHERE A1.PRO_ID = #{proId} AND A1.C_ESNTL_ID = #{reqEsntlId}
AND A1.P_ESNTL_ID = #{pEsntlId}
ORDER BY A1.PRO_SEQ DESC, A1.REQ_DT DESC LIMIT 1

SELECT COALESCE(A1.REQ_ID, '') AS REQ_ID , COALESCE(A1.PRO_ID, '') AS PRO_ID , COALESCE((SELECT P.PRO_GB FROM ARTPROM P WHERE P.PRO_ID = A1.PRO_ID LIMIT 1), '') AS PRO_GB , COALESCE(A1.PRO_SEQ, '0') AS PRO_SEQ , COALESCE(A1.REQ_PRO_SEQ, '0') AS REQ_PRO_SEQ , COALESCE(A1.REQ_ESNTL_ID, '') AS REQ_ESNTL_ID , COALESCE(A1.C_ESNTL_ID, '') AS C_ESNTL_ID , COALESCE(DECRYPT(U.USER_NM), '') AS USER_NM , COALESCE(FN_MASK_PHONE(COALESCE(DECRYPT(U.MBTLNUM), ''), 'N'), '') AS C_MBTLNUM , COALESCE(U.SEXDSTN_CODE, '') AS C_SEXDSTN_CODE , COALESCE(U.BRTHDY, '') AS C_BRTHDY , COALESCE(DECRYPT(A1.HEAD_NM), '') AS HEAD_NM , COALESCE(A1.P_ESNTL_ID, '') AS P_ESNTL_ID , COALESCE(DECRYPT(A1.P_USER_NM), '') AS P_USER_NM , COALESCE(A1.PRO_TYPE, '') AS PRO_TYPE , CASE WHEN A1.PRO_TYPE = '01' THEN '1인탐구형' WHEN A1.PRO_TYPE = '02' THEN '모둠탐구형' ELSE '' END AS PRO_TYPE_NM , COALESCE(FN_MASK_PHONE(COALESCE(DECRYPT(A1.MBTLNUM), ''), 'N'), '') AS MBTLNUM , COALESCE(A1.BRTHDY, '') AS BRTHDY , COALESCE(DECRYPT(A1.P_IHIDNUM), '') AS P_IHIDNUM , COALESCE(DECRYPT(A1.C_IHIDNUM), '') AS C_IHIDNUM , COALESCE(A1.CERT_YN, 'N') AS CERT_YN , COALESCE(A1.SCHOOL_ID, '') AS SCHOOL_ID , COALESCE(A1.SCHOOL_GB, '') AS SCHOOL_GB , COALESCE(A1.SCHOOL_NM, '') AS SCHOOL_NM , COALESCE(A1.SCHOOL_LVL, 0) AS SCHOOL_LVL , COALESCE(A1.SCHOOL_NO, 0) AS SCHOOL_NO , CASE WHEN A1.SCHOOL_LVL IS NOT NULL AND A1.SCHOOL_NO IS NOT NULL THEN CONCAT(A1.SCHOOL_LVL, '학년 ', A1.SCHOOL_NO, '반') WHEN A1.SCHOOL_LVL IS NOT NULL THEN CONCAT(A1.SCHOOL_LVL, '학년') WHEN A1.SCHOOL_NO IS NOT NULL THEN CONCAT(A1.SCHOOL_NO, '반') ELSE '' END AS SCHOOL_CLASS , COALESCE(A1.PAY_BANK_CODE, '') AS PAY_BANK_CODE , COALESCE((select CODE_NM from LETTCCMMNDETAILCODE where CODE_ID = 'ARM002' and CODE = A1.PAY_BANK_CODE), '' ) as PAY_BANK_CODE_NM , COALESCE(A1.PAY_BANK, '') AS PAY_BANK , COALESCE(A1.HOLDER_NM, '') AS HOLDER_NM , COALESCE(A1.REQ_PART, '') AS REQ_PART , COALESCE(A1.PLAY_PART, '') AS PLAY_PART , COALESCE(A1.REQ_OBJ, '') AS REQ_OBJ , COALESCE(A1.REQ_PLAY, '') AS REQ_PLAY , COALESCE(A1.REQ_PLAN, '') AS REQ_PLAN , COALESCE(A1.MCHIL_YN, 'N') AS MCHIL_YN , COALESCE(A1.MCHIL_NM, '') AS MCHIL_NM , COALESCE(A1.REQ_DESC, '') AS REQ_DESC , COALESCE(A1.FILE_ID, '') AS FILE_ID , COALESCE(A1.STUDY_CERT, '') AS STUDY_CERT , COALESCE(A1.RESULT_GB, '') AS RESULT_GB , A1.REQ_DT , A1.APRR_DT , A1.CHG_DT , A1.STOP_DT , COALESCE(A1.REA_DESC, '') AS REA_DESC , DATE_FORMAT(A1.WORK_DT, '%Y-%m-%d') AS WORK_DT , COALESCE(A1.STTUS_CODE, '') AS STTUS_CODE , CASE WHEN A1.STTUS_CODE = '01' THEN '임시저장' WHEN A1.STTUS_CODE = '02' THEN '신청' WHEN A1.STTUS_CODE = '03' THEN '승인' WHEN A1.STTUS_CODE = '04' THEN '완료' WHEN A1.STTUS_CODE = '11' THEN '반려' WHEN A1.STTUS_CODE = '12' THEN '중단' WHEN A1.STTUS_CODE = '99' THEN '취소' ELSE '' END AS STTUS_CODE_NM , COALESCE(A1.CHG_USER_ID, '') AS CHG_USER_ID , A1.CRT_DATE , A1.CHG_DATE , COALESCE(DECRYPT(U.ZIP), '') AS ZIP , COALESCE(DECRYPT(U.ADRES), '') AS ADRES , COALESCE(DECRYPT(U.DETAIL_ADRES), '') AS DETAIL_ADRES , COALESCE(CONCAT(DECRYPT(U.ADRES), ' ', DECRYPT(U.DETAIL_ADRES)), '') AS FULL_ADRES , COALESCE(PU.RELATION_GB, 'M') AS RELATION_GB , CASE WHEN PU.RELATION_GB = 'F' THEN '부' WHEN PU.RELATION_GB = 'M' THEN '모' WHEN PU.RELATION_GB = 'E' THEN '기타' ELSE '' END AS RELATION_GB_NM , COALESCE(U.FARM_YN, 'N') AS FARM_YN , COALESCE(U.FARM_DESC, '') AS FARM_DESC , COALESCE(AP.PRO_GBN, '') AS APPS_PRO_GBN , COALESCE(AP.PRO_GBN_ETC, '') AS APPS_PRO_GBN_ETC , COALESCE(AP.REQ_SUB, '') AS APPS_REQ_SUB , COALESCE(AP.JOIN_CNT, '') AS APPS_JOIN_CNT , COALESCE(AP.BEF_JOIN, '') AS APPS_BEF_JOIN , COALESCE(AP.JOIN_TIME, '') AS APPS_JOIN_TIME , COALESCE(AP.JOIN_TIME_CON, '') AS APPS_JOIN_TIME_CON , COALESCE(AP.S_UNDER, '') AS APPS_S_UNDER , COALESCE(AP.S_TARGET, '') AS APPS_S_TARGET , COALESCE(AP.S_CHAR, '') AS APPS_S_CHAR , COALESCE(AP.S_REASON, '') AS APPS_S_REASON , COALESCE(AP.S_EXPECT, '') AS APPS_S_EXPECT , COALESCE(AP.S_APPR, '') AS APPS_S_APPR , COALESCE(AP.S_COMM, '') AS APPS_S_COMM , COALESCE(AP.AGREE1_YN, 'N') AS APPS_AGREE1_YN , COALESCE(AP.AGREE2_YN, 'N') AS APPS_AGREE2_YN , COALESCE(AP.AGREE3_YN, 'N') AS APPS_AGREE3_YN FROM ARTAPPM A1 LEFT JOIN ARMUSER U ON A1.C_ESNTL_ID = U.ESNTL_ID LEFT JOIN ARMUSER PU ON A1.P_ESNTL_ID = PU.ESNTL_ID LEFT JOIN ARTAPPS AP ON A1.REQ_ID = AP.REQ_ID WHERE 1 = 1
AND A1.REQ_ID = #{reqId}
AND A1.PRO_ID = #{proId} AND A1.PRO_SEQ = #{proSeq} AND A1.C_ESNTL_ID = #{reqEsntlId}
AND A1.WORK_DT = #{workDt}

SELECT COUNT(*)
FROM ARTAPPM
WHERE PRO_ID = #{proId}
  AND PRO_SEQ = COALESCE(#{proSeq}, '0')


  AND C_ESNTL_ID = #{cEsntlId}


  AND REQ_ESNTL_ID = #{reqEsntlId}

SELECT COUNT(*)
FROM ARTAPPM
WHERE PRO_ID = #{proId}
  AND PRO_SEQ = COALESCE(#{proSeq}, '0')


  AND C_ESNTL_ID = #{cEsntlId}


  AND REQ_ESNTL_ID = #{reqEsntlId}


  AND WORK_DT = #{workDt}

SELECT COUNT(*)
FROM ARTAPPM
WHERE PRO_ID = #{proId}


  AND C_ESNTL_ID = #{cEsntlId}


  AND REQ_ESNTL_ID = #{reqEsntlId}

SELECT CAST(COALESCE(NULLIF(TRIM(P.REC_CNT), ''), '0') AS UNSIGNED) AS REC_CNT
  FROM ARTPROD P
 WHERE P.PRO_ID = #{proId}
   AND P.PRO_SEQ = #{proSeq}
   AND P.STTUS_CODE = 'A'
 FOR UPDATE

SELECT COUNT(*)
  FROM ARTAPPM
 WHERE PRO_ID = #{proId}
   AND PRO_SEQ = #{proSeq}
   AND STTUS_CODE IN ('03', '04')

mapper.update:
UPDATE ARTAPPM
   SET FILE_ID = NULL
 WHERE REQ_ID = #{reqId}

UPDATE ARTAPPM
   SET RESULT_GB = #{resultGb},
       CHG_DATE = NOW(),
       CHG_USER_ID = #{chgUserId}
 WHERE REQ_ID = #{reqId}

mapper.select:
SELECT * FROM ( SELECT ROW_NUMBER() OVER (ORDER BY F.UPLOAD_DTTM DESC, A1.PRO_ID, F.SEQ) AS RNUM , COALESCE(A1.REQ_ID, '') AS REQ_ID , COALESCE(A1.PRO_ID, '') AS PRO_ID , COALESCE(A1.PRO_SEQ, '0') AS PRO_SEQ , COALESCE(A1.REQ_ESNTL_ID, '') AS REQ_ESNTL_ID , COALESCE(A1.C_ESNTL_ID, '') AS C_ESNTL_ID , F.FILE_ID AS FILE_ID , F.SEQ AS SEQ , F.UPLOAD_DTTM AS UPLOAD_DTTM , COALESCE(F.FILE_DESC, '') AS FILE_DESC FROM ARTAPPM A1 INNER JOIN ARTFILE F ON A1.STUDY_CERT = F.FILE_ID AND F.STTUS_CODE = 'A' WHERE A1.STUDY_CERT IS NOT NULL AND TRIM(A1.STUDY_CERT) != ''
AND A1.REQ_ID = #{searchReqId}
AND A1.PRO_ID = #{searchProId} AND A1.PRO_SEQ = #{searchProSeq} AND A1.C_ESNTL_ID = #{searchReqEsntlId}
) A0 LIMIT #{lengthPage} OFFSET #{startIndex}

SELECT * FROM ( SELECT ROW_NUMBER() OVER (ORDER BY F.UPLOAD_DTTM DESC, A1.PRO_ID, F.SEQ) AS RNUM , COALESCE(A1.REQ_ID, '') AS REQ_ID , COALESCE(A1.PRO_ID, '') AS PRO_ID , COALESCE(A1.PRO_SEQ, '0') AS PRO_SEQ , COALESCE(A1.REQ_ESNTL_ID, '') AS REQ_ESNTL_ID , COALESCE(A1.C_ESNTL_ID, '') AS C_ESNTL_ID , F.FILE_ID AS FILE_ID , F.SEQ AS SEQ , F.UPLOAD_DTTM AS UPLOAD_DTTM , COALESCE(F.FILE_DESC, '') AS FILE_DESC FROM ARTAPPM A1 INNER JOIN ARTFILE F ON A1.STUDY_CERT = F.FILE_ID AND F.STTUS_CODE = 'A' WHERE A1.STUDY_CERT IS NOT NULL AND TRIM(A1.STUDY_CERT) != ''
AND A1.REQ_ID = #{searchReqId}
AND A1.PRO_ID = #{searchProId} AND A1.PRO_SEQ = #{searchProSeq} AND A1.C_ESNTL_ID = #{searchReqEsntlId}
) A0

SELECT * FROM ( SELECT ROW_NUMBER() OVER (ORDER BY F.UPLOAD_DTTM DESC, A1.PRO_ID, F.SEQ) AS RNUM , COALESCE(A1.REQ_ID, '') AS REQ_ID , COALESCE(A1.PRO_ID, '') AS PRO_ID , COALESCE(A1.PRO_SEQ, '0') AS PRO_SEQ , COALESCE(A1.REQ_ESNTL_ID, '') AS REQ_ESNTL_ID , COALESCE(A1.C_ESNTL_ID, '') AS C_ESNTL_ID , F.FILE_ID AS FILE_ID , F.SEQ AS SEQ , F.UPLOAD_DTTM AS UPLOAD_DTTM , COALESCE(F.FILE_DESC, '') AS FILE_DESC FROM ARTAPPM A1 INNER JOIN ARTFILE F ON A1.STUDY_CERT = F.FILE_ID AND F.STTUS_CODE = 'A' WHERE A1.STUDY_CERT IS NOT NULL AND TRIM(A1.STUDY_CERT) != ''
AND A1.REQ_ID = #{searchReqId}
AND A1.PRO_ID = #{searchProId} AND A1.PRO_SEQ = #{searchProSeq} AND A1.C_ESNTL_ID = #{searchReqEsntlId}
) A0

SELECT COUNT(1)
  FROM ARTAPPM A1
  INNER JOIN ARTFILE F
    ON A1.STUDY_CERT = F.FILE_ID
    AND F.STTUS_CODE = 'A'
 WHERE A1.STUDY_CERT IS NOT NULL
   AND TRIM(A1.STUDY_CERT) != ''


   AND A1.REQ_ID = #{searchReqId}


   AND A1.PRO_ID = #{searchProId}
   AND A1.PRO_SEQ = #{searchProSeq}
   AND A1.C_ESNTL_ID = #{searchReqEsntlId}

SELECT F.UPLOAD_DTTM AS UPLOAD_DTTM
     , COALESCE(F.FILE_DESC, '') AS FILE_DESC
     , CAST(F.FILE_ID AS CHAR) AS FILE_ID
     , F.SEQ AS SEQ
     , COALESCE(F.ORGF_NM, '') AS ORGF_NM
  FROM ARTAPPM A1
  INNER JOIN ARTFILE F
    ON A1.STUDY_CERT = F.FILE_ID
    AND F.STTUS_CODE = 'A'



            A1.REQ_ID = #{reqId}


            A1.PRO_ID = #{proId}
            AND A1.PRO_SEQ = #{proSeq}
            AND A1.C_ESNTL_ID = #{reqEsntlId}


    AND F.SEQ = #{seq}

SELECT COUNT(1)
  FROM ARTAPMM
 WHERE PRO_ID = #{proId}
   AND PRO_SEQ = COALESCE(#{proSeq}, 0)
   AND REQ_ESNTL_ID = #{reqEsntlId}
   AND (STTUS_CODE IS NULL OR STTUS_CODE != 'D')

   AND REQ_ID != #{excludeReqId}
